class Solution:
    def maximumLength(self, s):
        n = len(s)
        runs = {}
        i = 0
        while i < n:
            j = i
            while j < n and s[j] == s[i]:
                j += 1
            c = s[i]
            runs.setdefault(c, []).append(j - i)
            i = j
        for k in range(n, 0, -1):
            for lst in runs.values():
                total = 0
                for r in lst:
                    if r >= k:
                        total += r - k + 1
                if total >= 3:
                    return k
        return -1

