var maximumLength = function(s) {
    const runs = {};
    const n = s.length;
    let i = 0;
    while (i < n) {
        let j = i;
        while (j < n && s[j] === s[i]) j++;
        const length = j - i;
        const c = s[i];
        if (!runs[c]) runs[c] = [];
        runs[c].push(length);
        runs[c].sort((a, b) => b - a);
        if (runs[c].length > 3) runs[c].pop();
        i = j;
    }
    let ans = -1;
    for (const c in runs) {
        const lst = runs[c];
        const r1 = lst[0] || 0;
        const r2 = lst[1] || 0;
        const r3 = lst[2] || 0;
        if (r1 >= 3) ans = Math.max(ans, r1 - 2);
        if (r1 >= 1 && r2 >= 1) {
            const cand = Math.min(r1 - 1, r2);
            if (cand >= 1) ans = Math.max(ans, cand);
        }
        if (r3 >= 1) ans = Math.max(ans, r3);
    }
    return ans;
};
